import sys
import os
import mmap
import ctypes
import tempfile
import subprocess
from multiprocessing import Pool, cpu_count


# We'll try to compile a C extension for the inner loop
C_CODE = r"""
#include <stdio.h>
#include <string.h>
#include <stdlib.h>
#include <stdint.h>

// Hash map entry
#define HASH_SIZE (1 << 17)  // 131072 buckets
#define MAX_STATIONS 50000
#define MAX_NAME_LEN 128

typedef struct Entry {
    char name[MAX_NAME_LEN];
    int name_len;
    int32_t mn;
    int32_t mx;
    int64_t sum;
    int32_t count;
    struct Entry* next;
} Entry;

typedef struct {
    Entry* buckets[HASH_SIZE];
    Entry pool[MAX_STATIONS];
    int pool_idx;
} HashMap;

static inline uint32_t hash_bytes(const char* s, int len) {
    uint32_t h = 0x811c9dc5u;
    for (int i = 0; i < len; i++) {
        h ^= (uint8_t)s[i];
        h *= 0x01000193u;
    }
    return h;
}

static Entry* get_or_create(HashMap* map, const char* name, int name_len, int32_t val) {
    uint32_t h = hash_bytes(name, name_len) & (HASH_SIZE - 1);
    Entry* e = map->buckets[h];
    while (e) {
        if (e->name_len == name_len && memcmp(e->name, name, name_len) == 0) {
            return e;
        }
        e = e->next;
    }
    // Create new
    e = &map->pool[map->pool_idx++];
    memcpy(e->name, name, name_len);
    e->name_len = name_len;
    e->mn = val;
    e->mx = val;
    e->sum = val;
    e->count = 1;
    e->next = map->buckets[h];
    map->buckets[h] = e;
    return NULL;  // signals new entry was created
}

// Returns number of stations found
// Output format: name\0mn\0mx\0mean_numerator\0count per station
int process_chunk(const char* data, size_t len,
                  char* out_names, int* out_name_lens,
                  int32_t* out_mn, int32_t* out_mx,
                  int64_t* out_sum, int32_t* out_count) {
    HashMap* map = (HashMap*)calloc(1, sizeof(HashMap));
    if (!map) return -1;

    const char* p = data;
    const char* end = data + len;

    while (p < end) {
        // Find semicolon
        const char* semi = (const char*)memchr(p, ';', end - p);
        if (!semi) break;
        int name_len = semi - p;

        // Find newline
        const char* nl = (const char*)memchr(semi + 1, '\n', end - semi - 1);
        const char* line_end = nl ? nl : end;

        // Parse temperature
        const char* t = semi + 1;
        int tlen = line_end - t;
        int32_t val = 0;
        int neg = 0;
        int ti = 0;
        if (t[0] == '-') { neg = 1; ti = 1; }
        while (ti < tlen) {
            if (t[ti] == '.') { ti++; if (ti < tlen) val = val*10 + (t[ti]-'0'); break; }
            val = val*10 + (t[ti]-'0');
            ti++;
        }
        if (neg) val = -val;

        // Lookup / insert
        uint32_t h = hash_bytes(p, name_len) & (HASH_SIZE - 1);
        Entry* e = map->buckets[h];
        while (e) {
            if (e->name_len == name_len && memcmp(e->name, p, name_len) == 0) break;
            e = e->next;
        }
        if (e) {
            if (val < e->mn) e->mn = val;
            if (val > e->mx) e->mx = val;
            e->sum += val;
            e->count++;
        } else {
            e = &map->pool[map->pool_idx++];
            memcpy(e->name, p, name_len);
            e->name[name_len] = 0;
            e->name_len = name_len;
            e->mn = val; e->mx = val; e->sum = val; e->count = 1;
            e->next = map->buckets[h];
            map->buckets[h] = e;
        }

        p = nl ? nl + 1 : end;
    }

    // Copy results out
    int n = map->pool_idx;
    char* np = out_names;
    for (int i = 0; i < n; i++) {
        Entry* e = &map->pool[i];
        memcpy(np, e->name, e->name_len);
        out_name_lens[i] = e->name_len;
        np += e->name_len;
        out_mn[i] = e->mn;
        out_mx[i] = e->mx;
        out_sum[i] = e->sum;
        out_count[i] = e->count;
    }

    free(map);
    return n;
}
"""

_lib = None
_lib_path = None

def _compile_lib():
    global _lib, _lib_path
    if _lib is not None:
        return _lib

    src_file = '/tmp/onebrc_fast.c'
    lib_file = '/tmp/onebrc_fast.so'

    if not os.path.exists(lib_file):
        with open(src_file, 'w') as f:
            f.write(C_CODE)
        result = subprocess.run(
            ['cc', '-O3', '-march=native', '-shared', '-fPIC', '-o', lib_file, src_file],
            capture_output=True
        )
        if result.returncode != 0:
            return None

    try:
        lib = ctypes.CDLL(lib_file)
        lib.process_chunk.restype = ctypes.c_int
        lib.process_chunk.argtypes = [
            ctypes.c_char_p,
            ctypes.c_size_t,
            ctypes.c_char_p,
            ctypes.POINTER(ctypes.c_int),
            ctypes.POINTER(ctypes.c_int32),
            ctypes.POINTER(ctypes.c_int32),
            ctypes.POINTER(ctypes.c_int64),
            ctypes.POINTER(ctypes.c_int32),
        ]
        _lib = lib
        return lib
    except Exception:
        return None


def process_chunk_c(args):
    filepath, start, end = args

    lib = _compile_lib()

    with open(filepath, 'rb') as f:
        mm = mmap.mmap(f.fileno(), 0, access=mmap.ACCESS_READ)
        chunk = mm[start:end]
        mm.close()

    if lib is None:
        return process_chunk_python(chunk)

    MAX_STATIONS = 50000
    MAX_NAME_TOTAL = MAX_STATIONS * 128

    out_names = ctypes.create_string_buffer(MAX_NAME_TOTAL)
    out_name_lens = (ctypes.c_int * MAX_STATIONS)()
    out_mn = (ctypes.c_int32 * MAX_STATIONS)()
    out_mx = (ctypes.c_int32 * MAX_STATIONS)()
    out_sum = (ctypes.c_int64 * MAX_STATIONS)()
    out_count = (ctypes.c_int32 * MAX_STATIONS)()

    n = lib.process_chunk(
        chunk, len(chunk),
        out_names, out_name_lens,
        out_mn, out_mx, out_sum, out_count
    )

    if n < 0:
        return process_chunk_python(chunk)

    stats = {}
    name_offset = 0
    for i in range(n):
        nlen = out_name_lens[i]
        name = out_names.raw[name_offset:name_offset+nlen]
        name_offset += nlen
        stats[name] = [out_mn[i], out_mx[i], out_sum[i], out_count[i]]

    return stats


def process_chunk_python(chunk):
    stats = {}
    for line in chunk.split(b'\n'):
        if not line:
            continue
        station, sep, tb = line.partition(b';')
        if not sep:
            continue
        d0 = tb[-1] - 48
        if tb[0] == 45:
            if len(tb) == 4:
                val = -((tb[1] - 48) * 10 + d0)
            else:
                val = -((tb[1] - 48) * 100 + (tb[2] - 48) * 10 + d0)
        else:
            if len(tb) == 3:
                val = (tb[0] - 48) * 10 + d0
            else:
                val = (tb[0] - 48) * 100 + (tb[1] - 48) * 10 + d0
        entry = stats.get(station)
        if entry:
            if val < entry[0]: entry[0] = val
            if val > entry[1]: entry[1] = val
            entry[2] += val
            entry[3] += 1
        else:
            stats[station] = [val, val, val, 1]
    return stats


def merge_stats(all_stats):
    merged = {}
    for stats in all_stats:
        for station, (mn, mx, total, count) in stats.items():
            entry = merged.get(station)
            if entry:
                if mn < entry[0]: entry[0] = mn
                if mx > entry[1]: entry[1] = mx
                entry[2] += total
                entry[3] += count
            else:
                merged[station] = [mn, mx, total, count]
    return merged


def find_chunk_boundaries(filepath, num_chunks):
    size = os.path.getsize(filepath)
    chunk_size = size // num_chunks
    boundaries = []

    with open(filepath, 'rb') as f:
        start = 0
        for i in range(num_chunks):
            if i == num_chunks - 1:
                boundaries.append((start, size))
                break
            end = start + chunk_size
            if end >= size:
                boundaries.append((start, size))
                break
            f.seek(end)
            rest = f.read(4096)
            nl_pos = rest.find(b'\n')
            if nl_pos == -1:
                boundaries.append((start, size))
                break
            end = end + nl_pos + 1
            boundaries.append((start, end))
            start = end

    return boundaries


def main():
    if len(sys.argv) < 2:
        print("Usage: python solution.py <measurements_file>")
        sys.exit(1)

    filepath = sys.argv[1]

    # Compile the library first (before spawning workers)
    _compile_lib()

    num_workers = cpu_count()
    num_chunks = num_workers * 8

    boundaries = find_chunk_boundaries(filepath, num_chunks)
    args = [(filepath, start, end) for start, end in boundaries]

    with Pool(processes=num_workers) as pool:
        all_stats = pool.map(process_chunk_c, args)

    merged = merge_stats(all_stats)

    results = []
    for station, (mn, mx, total, count) in merged.items():
        mean_val = total / count
        results.append((
            station.decode('utf-8'),
            mn / 10.0,
            mx / 10.0,
            mean_val / 10.0
        ))

    results.sort(key=lambda x: x[0])

    out = [f"{s}={mn:.1f}/{mean:.1f}/{mx:.1f}" for s, mn, mx, mean in results]
    print("{" + ", ".join(out) + "}")


if __name__ == "__main__":
    main()

