import mmap
import subprocess
import ctypes
from multiprocessing import Pool, cpu_count


C_CODE = r"""
#include <string.h>
#include <stdlib.h>
#include <stdint.h>

#define HASH_SIZE (1 << 17)
#define MAX_STATIONS 55000
#define MAX_NAME_LEN 128

typedef struct Entry {
    uint8_t name[MAX_NAME_LEN];
    int32_t name_len;
    int32_t mn;
    int32_t mx;
    int64_t sum;
    int32_t count;
    int32_t next;  /* index into pool, -1 = none */
} Entry;

typedef struct {
    int32_t buckets[HASH_SIZE];
    Entry pool[MAX_STATIONS];
    int32_t pool_idx;
} HashMap;

static uint32_t hash_bytes(const uint8_t* s, int len) {
    uint32_t h = 2166136261u;
    for (int i = 0; i < len; i++) {
        h ^= s[i];
        h *= 16777619u;
    }
    return h;
}

int process_chunk(
    const uint8_t* data, size_t len,
    uint8_t* out_names, int32_t* out_name_lens,
    int32_t* out_mn, int32_t* out_mx,
    int64_t* out_sum, int32_t* out_count
) {
    HashMap* map = (HashMap*)calloc(1, sizeof(HashMap));
    if (!map) return -1;
    memset(map->buckets, -1, sizeof(map->buckets));

    const uint8_t* p = data;
    const uint8_t* end = data + len;

    while (p < end) {
        const uint8_t* semi = (const uint8_t*)memchr(p, ';', end - p);
